/** Header fields — form model (not API DTO). */

export interface CashVoucherHeaderModel {
  voucherDate: string;
  voucherNumber: string;
  receiptKind: string;
  currencyCode: string;
  exchangeRate: string;
  customerId: string;
  customerCode: string;
  /** Tên hiển thị từ CustomerSearchField — display-only */
  customerName: string;
  /** Loại ĐT (Customer/Supplier/Both) — display-only, từ lookup */
  customerType: string;
  /** Người đại diện — nhập/sửa độc lập với đối tượng */
  representativeName: string;
  customerPhone: string;
  reference: string;
  referenceCustomerName: string;
  accountCode: string;
  accountName: string;
  counterAccountCode: string;
  counterAccountName: string;
  description: string;
  processingLevel: string;
  postingReasonCode: string;
  paymentChannelCode: string;
}

export type CashVoucherHeaderKey = keyof CashVoucherHeaderModel;

export const defaultCashVoucherHeader = (): CashVoucherHeaderModel => ({
  voucherDate: new Date().toISOString().slice(0, 10),
  voucherNumber: '',
  receiptKind: '2',
  currencyCode: '',
  exchangeRate: '',
  customerId: '',
  customerCode: '',
  customerName: '',
  customerType: '',
  representativeName: '',
  customerPhone: '',
  reference: '',
  referenceCustomerName: '',
  accountCode: '',
  accountName: '',
  counterAccountCode: '',
  counterAccountName: '',
  description: '',
  processingLevel: '',
  postingReasonCode: '',
  paymentChannelCode: '',
});

/** Display-only — excluded from dirty (initialValue tracks hydrate). */
export const CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS: CashVoucherHeaderKey[] = [
  'voucherNumber',
  'customerName',
  'customerType',
  'accountName',
  'referenceCustomerName',
  'counterAccountName',
];
